class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        unordered_map<char, int> charVals;
        for (int i = 0; i < chars.size(); ++i) {
            charVals[chars[i]] = vals[i];
        }

        int maxCost = 0, currentCost = 0;
        for (char c : s) {
            int val = charVals.count(c) ? charVals[c] : c - 'a' + 1;
            currentCost = max(val, currentCost + val);
            maxCost = max(maxCost, currentCost);
        }

        return maxCost;
    }
};
